/**
 * API: Propose Schedule (Provider)
 * Provider proposes a date/time for a service in OPEN_FOR_SCHEDULE status.
 */
app.post('/api/services/:id/propose-schedule', async (c) => {
    const serviceId = c.req.param('id');
    const { scheduled_at } = await c.req.json();
    const authHeader = c.req.header('Authorization');
    const db = c.env.DB;

    if (!scheduled_at) return c.json({ success: false, message: "Missing scheduled_at" }, 400);

    try {
        let providerId = null;
        if (authHeader && authHeader.startsWith('Bearer ')) {
            const token = authHeader.substring(7);
            const decoded = decodeJwt(token);
            if (decoded && decoded.email) {
                const u: any = await db.prepare('SELECT id FROM users WHERE email = ?').bind(decoded.email).first();
                if (u) providerId = u.id;
            }
        }

        if (!providerId) return c.json({ success: false, message: "Unauthorized" }, 401);

        // Verify service status
        const service: any = await db.prepare("SELECT status FROM service_requests_new WHERE id = ?").bind(serviceId).first();
        if (!service) return c.json({ success: false, message: "Service not found" }, 404);

        if (service.status !== 'open_for_schedule' && service.status !== 'schedule_proposed') {
            return c.json({ success: false, message: "Service not open for scheduling" }, 400);
        }

        // Update service
        await db.prepare(`
            UPDATE service_requests_new
            SET status = 'schedule_proposed',
                provider_id = ?,
                scheduled_at = ?
            WHERE id = ?
        `).bind(providerId, scheduled_at, serviceId).run();

        // Notify Client (via Sync/RTDB Pulse)
        c.executionCtx.waitUntil((async () => {
            const s: any = await db.prepare("SELECT client_id FROM service_requests_new WHERE id = ?").bind(serviceId).first();
            if (s) {
                // @ts-ignore
                await syncStatusToFirebase(c.env, serviceId, 'schedule_proposed', [s.client_id, providerId], { scheduled_at });
            }
        })());

        LOG.sucesso(`📅 Proposta de agendamento enviada por Prestador ${providerId} para Serviço ${serviceId} em ${scheduled_at}`);
        return c.json({ success: true });

    } catch (e: any) {
        LOG.erro(`Erro ao propor agendamento:`, e);
        return c.json({ success: false, error: e.message }, 500);
    }
});

/**
 * API: Confirm Schedule (Client)
 * Client accepts the proposed schedule.
 */
app.post('/api/services/:id/confirm-schedule', async (c) => {
    const serviceId = c.req.param('id');
    const db = c.env.DB;

    try {
        // Verify service status
        const service: any = await db.prepare("SELECT status, provider_id, client_id, scheduled_at FROM service_requests_new WHERE id = ?").bind(serviceId).first();

        if (!service) return c.json({ success: false, message: "Service not found" }, 404);
        if (service.status !== 'schedule_proposed') {
            return c.json({ success: false, message: "No schedule proposal to confirm" }, 400);
        }

        // Update status to SCHEDULED
        await db.prepare(`
            UPDATE service_requests_new
            SET status = 'scheduled'
            WHERE id = ?
        `).bind(serviceId).run();

        // Sync updates
        c.executionCtx.waitUntil((async () => {
            // @ts-ignore
            await syncStatusToFirebase(c.env, serviceId, 'scheduled', [service.client_id, service.provider_id], { scheduled_at: service.scheduled_at });
        })());

        LOG.sucesso(`📅 Agendamento CONFIRMADO para Serviço ${serviceId}`);
        return c.json({ success: true });

    } catch (e: any) {
        LOG.erro(`Erro ao confirmar agendamento:`, e);
        return c.json({ success: false, error: e.message }, 500);
    }
});

