app.post('/api/services/:id/propose-schedule', async (c) => {
    const serviceId = c.req.param('id');
    const { scheduled_at } = await c.req.json();
    const db = c.env.DB;
    const authHeader = c.req.header('Authorization');

    try {
        let providerId = null;
        if (authHeader?.startsWith('Bearer ')) {
            const token = authHeader.substring(7);
            const decoded = decodeJwt(token);
            if (decoded?.email) {
                const u: any = await db.prepare('SELECT id FROM users WHERE email = ?').bind(decoded.email).first();
                if (u) providerId = u.id;
            }
        }

        if (!providerId) return c.json({ success: false, message: 'Não autorizado' }, 401);
        if (!scheduled_at) return c.json({ success: false, message: 'Data/Hora necessária' }, 400);

        // Maestro v2: Proposta de Agendamento e Sincronização
        await updateServiceStatus(
            c.env,
            serviceId,
            'schedule_proposed',
            [], // Sincronização manual abaixo para dados extras
            {},
            { provider_id: providerId, scheduled_at: scheduled_at },
            "id = ? AND status IN ('open_for_schedule', 'schedule_proposed', 'pending', 'paid', 'offered')"
        );

        // Notify client with extra scheduling data
        c.executionCtx.waitUntil((async () => {
            const service: any = await db.prepare('SELECT client_id FROM service_requests_new WHERE id = ?').bind(serviceId).first();
            if (service) {
                await syncStatusToFirebase(c.env, serviceId, 'schedule_proposed', [service.client_id, providerId], {
                    scheduled_at,
                    proposed_by: providerId
                });
            }
        })());

        return c.json({ success: true });
    } catch (e: any) {
        return c.json({ success: false, error: e.message }, 500);
    }
});

